using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // [Breaking] Discriminator property renamed from "Discriminator" to "$type" in EF9.
            // Existing 500K documents use "Discriminator" — keep the old name for compatibility.
            entity.HasDiscriminator<string>("Discriminator");

            // [Breaking] EF9 id format changed from "Product|123" to just "123".
            // Existing documents use the "Product|123" format — preserve it.
            entity.HasDiscriminatorInJsonId();

            // [Breaking] EF9 maps the key property directly to JSON "id", removing
            // the separate shadow __id property. Keep the EF8 shadow-id behavior so
            // existing documents that store "Id" as a separate JSON field still work.
            entity.HasShadowId();
        });

        // [Breaking] HasIndex() now throws for Cosmos — removed.
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

